+/**
+ * Helper for hermes_watcher state persistence.
+ *
+ * Rule: last_check_iso must ONLY advance on a successful upstream API response.
+ * Failures must be logged as structured errors and must NOT update state, so
+ * outage windows remain visible to operators and downstream alerting.
+ */
+
+export type HermesCheckResult =
+  | { ok: true; checkedAt: string; payload: unknown }
+  | { ok: false; error: string };
+
+export interface HermesState {
+  last_check_iso?: string;
+}
+
+export function applyCheckResult(
+  state: HermesState,
+  result: HermesCheckResult,
+): HermesState {
+  if (result.ok) {
+    return { ...state, last_check_iso: result.checkedAt };
+  }
+  console.error(JSON.stringify({
+    level: 'ERROR',
+    event: 'hermes_watcher_api_failure',
+    error: result.error,
+    ts: new Date().toISOString(),
+  }));
+  return state; // do NOT advance last_check_iso on failure
+}

