+import path from 'node:path';
+import fs from 'node:fs';
+
+/**
+ * WORKSPACE_ROOT is resolved exactly once, at module load.
+ * It must be supplied via the SHINOBI_WORKSPACE_ROOT env var; falling back to
+ * process.cwd() is rejected because cwd may drift during agent execution and
+ * silently break path-traversal validation in permissions.ts.
+ */
+function resolveWorkspaceRoot(): string {
+  const raw = process.env.SHINOBI_WORKSPACE_ROOT;
+  if (!raw || raw.trim() === '') {
+    throw new Error(
+      'SHINOBI_WORKSPACE_ROOT env var is required and must be an absolute path',
+    );
+  }
+  const abs = path.resolve(raw);
+  if (!fs.existsSync(abs) || !fs.statSync(abs).isDirectory()) {
+    throw new Error(`SHINOBI_WORKSPACE_ROOT does not exist or is not a directory: ${abs}`);
+  }
+  return abs;
+}
+
+export const WORKSPACE_ROOT: string = resolveWorkspaceRoot();
+
+export function assertInsideWorkspace(p: string): void {
+  const resolved = path.resolve(p);
+  if (!resolved.startsWith(WORKSPACE_ROOT + path.sep) && resolved !== WORKSPACE_ROOT) {
+    throw new Error(`Path escapes WORKSPACE_ROOT: ${resolved}`);
+  }
+}

